def read_file_list(filename):
    with open(filename, 'r') as f:
        return [list(line.strip()) for line in f]

def read_input(input_file):
    antennas = {}
    input = read_file_list(input_file)
    for r, row in enumerate(input):
        for c, _ in enumerate(row):
            if row[c] != '.':
                antennas.setdefault(row[c], []).append((r, c))
    return input, antennas

def in_grid(position, grid):
    return 0 <= position[0] < len(grid) and 0 <= position[1] < len(grid[0])

def get_antinodes(antenna_1, antenna_2):
    antinode_1 = (antenna_1[0]-antenna_2[0], antenna_1[1]-antenna_2[1])
    antinode_2 = (antenna_1[0]+antenna_2[0], antenna_1[1]+antenna_2[1])
    return antinode_1, antinode_2

grid, antennas = read_input('input.txt')
antinode_1, antinode_2 = get_antinodes(antennas.get(list(antennas.keys())[0])[0], antennas.get(list(antennas.keys())[0])[1])
print(in_grid(antinode_1, grid))
print(in_grid(antinode_2, grid))

